// ============================================================
// Code: Nach Kunden aufteilen (v3)
// NEU: ConfluenceSync-Filter + Hash-Check für Änderungserkennung
//
// Felder in DB Termine (neu benötigt):
//   ConfluenceSync  | Checkbox   | true = bereits übertragen
//   LastSyncHash    | Rich Text  | hash(datum+titel) vom letzten Sync
//
// Logik:
//   ConfluenceSync=false → immer übertragen (neuer Termin)
//   ConfluenceSync=true  → nur wenn hash(datum+titel) != LastSyncHash
// ============================================================

var items = $input.all();
var today = new Date();
today.setHours(0, 0, 0, 0);

// Einfache Hash-Funktion (djb2) – kein crypto nötig
function simpleHash(str) {
  var hash = 5381;
  for (var i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash; // 32bit int
  }
  return String(Math.abs(hash));
}

var kundeMap = {};

for (var i = 0; i < items.length; i++) {
  var props = items[i].json;
  var notionPageId = items[i].json.id || '';

  // --- Datum prüfen ---
  var datumObj = props.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start) { datumRaw = datumObj.start; }
  else if (typeof datumObj === 'string' && datumObj.length >= 10) { datumRaw = datumObj; }
  if (!datumRaw) continue;

  var terminDate = new Date(datumRaw.substring(0, 10));
  if (terminDate < today) continue;

  // --- Termin-Felder ---
  var titel      = props.property_titel || props.name || 'Kein Titel';
  var ort        = props.property_ort || '';
  var datumIso   = datumRaw.substring(0, 10);
  var dp         = datumIso.split('-');
  var datumStr   = dp[2] + '.' + dp[1] + '.' + dp[0];
  var uhrzeitStr = '';
  var tIdx = datumRaw.indexOf('T');
  if (tIdx !== -1) { uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6); }

  // --- NEU: ConfluenceSync + LastSyncHash ---
  var confluenceSync = props.property_confluence_sync
    || props.property_confluencesync
    || false;

  var lastSyncHash = props.property_last_sync_hash
    || props.property_lastsynchash
    || props.property_last_sync_hash
    || '';

  // Hash aus aktuellem Datum + Titel berechnen
  var currentHash = simpleHash(datumIso + '|' + titel);

  // Filter-Logik:
  // ConfluenceSync=false → neu, immer übertragen
  // ConfluenceSync=true  → nur wenn Hash geändert
  var needsSync = false;
  if (!confluenceSync) {
    needsSync = true; // Neuer Termin
  } else if (currentHash !== String(lastSyncHash).trim()) {
    needsSync = true; // Datum oder Titel geändert
  }

  if (!needsSync) continue; // Überspringen – keine Änderung

  // --- Kunden-Relation ---
  var kundenRaw = props.property_kunden || [];
  var kundenIds = Array.isArray(kundenRaw) ? kundenRaw : [kundenRaw];

  for (var j = 0; j < kundenIds.length; j++) {
    var kundePageId = kundenIds[j];
    if (!kundePageId) continue;
    if (!kundeMap[kundePageId]) {
      kundeMap[kundePageId] = { kundePageId: kundePageId, termine: [] };
    }
    kundeMap[kundePageId].termine.push({
      datumIso:    datumIso,
      datumStr:    datumStr,
      uhrzeitStr:  uhrzeitStr,
      titel:       titel,
      ort:         ort,
      notionPageId: notionPageId,  // für Notion-Update nach Sync
      currentHash:  currentHash    // für Notion-Update nach Sync
    });
  }
}

var result = [];
var kundeIds = Object.keys(kundeMap);
for (var ki = 0; ki < kundeIds.length; ki++) {
  var entry = kundeMap[kundeIds[ki]];
  entry.termine.sort(function(a, b) {
    return a.datumIso < b.datumIso ? -1 : a.datumIso > b.datumIso ? 1 : 0;
  });
  result.push({ json: entry });
}
return result;

// ============================================================
// Code: Tabelle aufbauen (v6)
// Fix: Geänderte Termine korrekt ersetzen
//
// Mechanismus:
//   - notionPageId wird als data-notion-id="..." auf <tr> gespeichert
//   - Beim Parsen: bestehende Zeilen nach notionPageId indiziert
//   - Neue/geänderte Termine ersetzen die alte Zeile (gleiche notionPageId)
//   - Vergangene Termine (< heute) werden entfernt
//   - Neue Termine (noch nicht in Tabelle) werden angehängt
//   - Sortierung nach Datum
//   - Confluence Cloud-Format: data-table-width, ac:local-id, <p>-Tags
// ============================================================

var page        = $json;
var loopItem    = $('Loop: Ein Kunde pro Durchlauf').item.json;
var neueTermine = loopItem.termine || [];

var esc = function(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
};
var unesc = function(s) {
  return String(s || '')
    .replace(/&amp;/g,  '&')
    .replace(/&lt;/g,   '<')
    .replace(/&gt;/g,   '>')
    .replace(/&quot;/g, '"')
    .replace(/<[^>]+>/g, ''); // alle Tags entfernen beim Parsen
};

var pageId       = page.id    || '';
var pageTitle    = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value)
  ? page.body.storage.value : '';

// ---------------------------------------------------------------
// Schritt 1: "Nächste Termine"-Panel finden
// ---------------------------------------------------------------
var panelTitles = [
  'N\u00e4chste Termine', 'N&auml;chste Termine',
  'N&#228;chste Termine', 'N&#xE4;chste Termine', 'N&#xe4;chste Termine'
];
var titleIdx = -1;
for (var ti = 0; ti < panelTitles.length; ti++) {
  titleIdx = html.indexOf(panelTitles[ti]);
  if (titleIdx !== -1) break;
}
if (titleIdx === -1) {
  throw new Error('Heading "Nächste Termine" nicht gefunden. pageId:' + pageId);
}

var panelMacroTag = '<ac:structured-macro ac:name="panel"';
var panelStart    = html.indexOf(panelMacroTag, titleIdx);
if (panelStart === -1) {
  throw new Error('Panel-Makro nach "Nächste Termine" nicht gefunden. pageId:' + pageId);
}
var panelEndTag   = '</ac:structured-macro>';
var panelEnd      = html.indexOf(panelEndTag, panelStart);
if (panelEnd === -1) {
  throw new Error('Panel-Ende nicht gefunden. pageId:' + pageId);
}
var panelEnd_full = panelEnd + panelEndTag.length;
var panelBlock    = html.substring(panelStart, panelEnd_full);

// ---------------------------------------------------------------
// Schritt 2: Bestehende Zeilen parsen
// Map: notionPageId → Termin-Objekt (für Ersetzung)
// Zeilen ohne notionPageId: nach datumIso|titel indiziert (Altbestand)
// ---------------------------------------------------------------
var today = new Date();
today.setHours(0, 0, 0, 0);

function deToIso(datumStr) {
  var parts = String(datumStr || '').trim().split('.');
  if (parts.length !== 3) return '';
  return parts[2] + '-' + parts[1] + '-' + parts[0];
}
function isoToDate(iso) {
  var d = new Date(iso);
  d.setHours(0, 0, 0, 0);
  return d;
}

// Map: notionPageId → Termin (für Ersetzung durch geänderte Termine)
var byNotionId = {};
// Map: datumIso|titel → Termin (Altbestand ohne notionPageId)
var byKey      = {};

var trPattern = /<tr[^>]*>([\s\S]*?)<\/tr>/g;
var trFullPattern = /<tr([^>]*)>([\s\S]*?)<\/tr>/g;
var trMatch;

// Reset regex
trFullPattern.lastIndex = 0;
while ((trMatch = trFullPattern.exec(panelBlock)) !== null) {
  var trAttrs  = trMatch[1]; // Attribute des <tr>-Tags
  var rowHtml  = trMatch[2];

  if (rowHtml.indexOf('<th') !== -1) continue; // Header überspringen

  // notionPageId aus data-notion-id Attribut lesen
  var notionIdMatch = trAttrs.match(/data-notion-id="([^"]+)"/);
  var notionPageId  = notionIdMatch ? notionIdMatch[1] : '';

  // Zellinhalte extrahieren
  var tdValues = [];
  var tdPattern = /<td[^>]*>([\s\S]*?)<\/td>/g;
  var tdMatch;
  while ((tdMatch = tdPattern.exec(rowHtml)) !== null) {
    tdValues.push(unesc(tdMatch[1].trim()));
  }
  if (tdValues.length < 4) continue;

  var datumStr   = tdValues[0];
  var uhrzeitStr = tdValues[1];
  var titel      = tdValues[2];
  var ort        = tdValues[3];
  var datumIso   = deToIso(datumStr);

  // Vergangene Termine entfernen
  if (datumIso && isoToDate(datumIso) < today) continue;

  var terminObj = { datumIso, datumStr, uhrzeitStr, titel, ort, notionPageId };

  if (notionPageId) {
    byNotionId[notionPageId] = terminObj;
  } else {
    byKey[datumIso + '|' + titel] = terminObj;
  }
}

// ---------------------------------------------------------------
// Schritt 3: Neue/geänderte Termine einpflegen
// - Hat notionPageId bereits einen Eintrag → ersetzen (Änderung)
// - Sonst: prüfen ob datumIso|titel schon existiert → überspringen
// - Sonst: neu anhängen
// ---------------------------------------------------------------
for (var ni = 0; ni < neueTermine.length; ni++) {
  var nt = neueTermine[ni];
  if (!nt.datumIso) continue;
  if (isoToDate(nt.datumIso) < today) continue;

  var newObj = {
    datumIso:    nt.datumIso,
    datumStr:    nt.datumStr,
    uhrzeitStr:  nt.uhrzeitStr,
    titel:       nt.titel,
    ort:         nt.ort,
    notionPageId: nt.notionPageId || ''
  };

  if (nt.notionPageId && byNotionId[nt.notionPageId]) {
    // Geänderter Termin → bestehende Zeile ersetzen
    byNotionId[nt.notionPageId] = newObj;
  } else if (!nt.notionPageId && byKey[nt.datumIso + '|' + nt.titel]) {
    // Altbestand-Duplikat → überspringen
  } else if (nt.notionPageId) {
    // Neuer Termin mit notionPageId → in byNotionId eintragen
    byNotionId[nt.notionPageId] = newObj;
  } else {
    // Neuer Termin ohne notionPageId → in byKey eintragen
    byKey[nt.datumIso + '|' + nt.titel] = newObj;
  }
}

// ---------------------------------------------------------------
// Schritt 4: Alle Termine zusammenführen und sortieren
// ---------------------------------------------------------------
var alleTermine = [];
var keys1 = Object.keys(byNotionId);
for (var k1 = 0; k1 < keys1.length; k1++) {
  alleTermine.push(byNotionId[keys1[k1]]);
}
var keys2 = Object.keys(byKey);
for (var k2 = 0; k2 < keys2.length; k2++) {
  alleTermine.push(byKey[keys2[k2]]);
}
alleTermine.sort(function(a, b) {
  return a.datumIso < b.datumIso ? -1 : a.datumIso > b.datumIso ? 1 : 0;
});

// ---------------------------------------------------------------
// Schritt 5: Confluence Cloud-kompatible Tabelle aufbauen
// ---------------------------------------------------------------
var tableLocalId = 'termine-tbl-' + pageId + '-0001';

var headerRow = '<tr>'
  + '<th ac:local-id="' + tableLocalId + '-h1"><p><strong>Datum</strong></p></th>'
  + '<th ac:local-id="' + tableLocalId + '-h2"><p><strong>Uhrzeit</strong></p></th>'
  + '<th ac:local-id="' + tableLocalId + '-h3"><p><strong>Titel</strong></p></th>'
  + '<th ac:local-id="' + tableLocalId + '-h4"><p><strong>Ort</strong></p></th>'
  + '</tr>';

var dataRows = '';
for (var ri = 0; ri < alleTermine.length; ri++) {
  var t     = alleTermine[ri];
  var rowId = tableLocalId + '-r' + ri;
  // notionPageId als data-Attribut auf <tr> speichern
  var notionAttr = t.notionPageId
    ? ' data-notion-id="' + esc(t.notionPageId) + '"'
    : '';
  dataRows += '<tr ac:local-id="' + rowId + '"' + notionAttr + '>'
    + '<td ac:local-id="' + rowId + '-c1"><p>' + esc(t.datumStr)   + '</p></td>'
    + '<td ac:local-id="' + rowId + '-c2"><p>' + esc(t.uhrzeitStr) + '</p></td>'
    + '<td ac:local-id="' + rowId + '-c3"><p>' + esc(t.titel)      + '</p></td>'
    + '<td ac:local-id="' + rowId + '-c4"><p>' + esc(t.ort)        + '</p></td>'
    + '</tr>';
}

var tableHtml = alleTermine.length > 0
  ? '<table data-table-width="760" data-layout="default" ac:local-id="' + tableLocalId + '">'
    + '<tbody>' + headerRow + dataRows + '</tbody>'
    + '</table>'
  : '<p></p>';

var newRichTextBody = '<ac:rich-text-body>' + tableHtml + '</ac:rich-text-body>';

// ---------------------------------------------------------------
// Schritt 6: Panel-Block ersetzen (self-closing oder befüllt)
// ---------------------------------------------------------------
var selfClosing  = '<ac:rich-text-body />';
var newPanelBlock;

if (panelBlock.indexOf(selfClosing) !== -1) {
  newPanelBlock = panelBlock.replace(selfClosing, newRichTextBody);
} else {
  var rtbOpen  = '<ac:rich-text-body>';
  var rtbClose = '</ac:rich-text-body>';
  var rtbStart = panelBlock.indexOf(rtbOpen);
  var rtbEnd   = panelBlock.indexOf(rtbClose);
  if (rtbStart === -1 || rtbEnd === -1) {
    throw new Error('ac:rich-text-body nicht gefunden. pageId:' + pageId
      + ' Panel:' + panelBlock.substring(0, 300));
  }
  newPanelBlock = panelBlock.substring(0, rtbStart)
    + newRichTextBody
    + panelBlock.substring(rtbEnd + rtbClose.length);
}

html = html.substring(0, panelStart) + newPanelBlock + html.substring(panelEnd_full);

return {
  json: {
    pageId:      pageId,
    pageTitle:   pageTitle,
    newVersion:  currentVersion + 1,
    updatedHtml: html
  }
};

// ============================================================
// Code: Sync-Items aufbereiten (FIXED)
// Mode: runOnceForAllItems  ← wichtig, nicht runOnceForEachItem
// Gibt pro Termin ein separates Item aus für Notion-Update
// ============================================================

var loopItem = $('Loop: Ein Kunde pro Durchlauf').item.json;
var termine  = loopItem.termine || [];

var result = [];
for (var i = 0; i < termine.length; i++) {
  var t = termine[i];
  if (!t.notionPageId) continue;
  result.push({
    json: {
      notionPageId: t.notionPageId,
      currentHash:  t.currentHash
    }
  });
}

// Sicherheit: mindestens ein leeres Item damit der Loop nicht bricht
if (result.length === 0) {
  result.push({ json: { notionPageId: '', currentHash: '' } });
}

return result;
